### Step 4: Update the existing AdapterCard test

Update or add tests in `apps/client/src/layers/features/relay/__tests__/AdapterCard.test.tsx`:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';

describe('AdapterCard error display', () => {
  it('renders Collapsible trigger when lastError is set', () => {
    // Render AdapterCard with a mock instance that has lastError set
    // Verify the trigger button with aria-label="Toggle full error message" is present
    const trigger = screen.getByRole('button', { name: 'Toggle full error message' });
    expect(trigger).toBeInTheDocument();
  });

  it('shows truncated error preview by default', () => {
    // The truncated preview should be visible
    // The full error block should NOT be visible
  });

  it('shows full error text when trigger is clicked', async () => {
    const user = userEvent.setup();
    // Click the trigger
    await user.click(screen.getByRole('button', { name: 'Toggle full error message' }));
    // The full error text in the monospace block should now be visible
  });

  it('trigger is keyboard accessible (Enter/Space)', async () => {
    const user = userEvent.setup();
    // Tab to the trigger
