Add full-stack binding update support: BindingStore.update() method, PATCH route, transport method, and TanStack Query mutation hook.

## Implementation Steps

### Step 1: Add update() to BindingStore

In `apps/server/src/services/relay/binding-store.ts`, add the `update()` method to the `BindingStore` class, after the `delete()` method:

```typescript
/**
 * Update an existing binding's mutable fields.
 *
 * @param id - The binding UUID to update
 * @param updates - Fields to update (sessionStrategy, label, chatId, channelType)
 * @returns The updated binding, or undefined if not found
 */
async update(
  id: string,
  updates: Partial<Pick<AdapterBinding, 'sessionStrategy' | 'label' | 'chatId' | 'channelType'>>,
): Promise<AdapterBinding | undefined> {
  const existing = this.bindings.get(id);
  if (!existing) return undefined;
  const updated: AdapterBinding = {
    ...existing,
    ...updates,
    updatedAt: new Date().toISOString(),
  };
  this.bindings.set(id, updated);
  await this.save();
  return updated;
}
```

### Step 2: Create Zod validation schema for updates

Add a validation schema in the relay route file or in `@dorkos/shared/relay-schemas`. The update schema should only allow the mutable fields:

```typescript
const UpdateBindingRequestSchema = z.object({
  sessionStrategy: z.enum(['per-chat', 'per-user', 'stateless']).optional(),
  label: z.string().optional(),
  chatId: z.string().optional(),
  channelType: ChannelTypeSchema.optional(),
}).strict(); // Reject unknown fields for security
```

If adding to `relay-schemas.ts`, export it with appropriate TSDoc. Otherwise, define it inline in the route handler as a local schema.

### Step 3: Add PATCH route

In `apps/server/src/routes/relay.ts`, add after the existing `DELETE /bindings/:id` route (around line 522):

```typescript
// PATCH /api/relay/bindings/:id — Update a binding's mutable fields
router.patch('/bindings/:id', async (req, res) => {
  const bindingStore = adapterManager.getBindingStore();
  if (!bindingStore) return res.status(503).json({ error: 'Binding subsystem not available' });
  const result = UpdateBindingRequestSchema.safeParse(req.body);
  if (!result.success) {
    return res.status(400).json({ error: 'Validation failed', details: result.error.flatten() });
  }
  const updated = await bindingStore.update(req.params.id, result.data);
  if (!updated) return res.status(404).json({ error: 'Binding not found' });
  return res.json({ binding: updated });
});
```

### Step 4: Add transport method

In `apps/client/src/layers/shared/lib/transport/relay-methods.ts`, add to the bindings section (after `deleteBinding`):

```typescript
updateBinding(
  id: string,
  updates: Partial<Pick<AdapterBinding, 'sessionStrategy' | 'label' | 'chatId' | 'channelType'>>,
): Promise<AdapterBinding> {
  return fetchJSON<{ binding: AdapterBinding }>(baseUrl, `/relay/bindings/${encodeURIComponent(id)}`, {
    method: 'PATCH',
    body: JSON.stringify(updates),
  }).then((r) => r.binding);
},
```

Also add `updateBinding` to the `Transport` interface in `packages/shared/src/transport.ts` if the interface is explicitly typed.

### Step 5: Create mutation hook

Create `apps/client/src/layers/entities/binding/model/use-update-binding.ts`:

```typescript
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useTransport } from '@/layers/shared/model';
import type { AdapterBinding } from '@dorkos/shared/relay-schemas';
import { BINDINGS_QUERY_KEY } from './use-bindings';

/**
 * Update an existing adapter-agent binding's mutable fields.
 * Invalidates the bindings cache on success.
 */
export function useUpdateBinding() {
  const transport = useTransport();
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: ({ id, updates }: {
      id: string;
      updates: Partial<Pick<AdapterBinding, 'sessionStrategy' | 'label' | 'chatId' | 'channelType'>>;
    }) => transport.updateBinding(id, updates),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [...BINDINGS_QUERY_KEY] });
    },
  });
}
```

### Step 6: Update barrel exports

In `apps/client/src/layers/entities/binding/index.ts`, add:
```typescript
export { useUpdateBinding } from './model/use-update-binding';
```

### Step 7: Write tests

**BindingStore update test** — add to `apps/server/src/services/relay/__tests__/binding-store.test.ts`:

```typescript
describe('BindingStore.update()', () => {
  it('updates mutable fields and saves to disk', async () => {
    const binding = await store.create({
      adapterId: 'telegram-1',
      agentId: 'agent-1',
      projectPath: '/project',
      sessionStrategy: 'per-chat',
    });
    const updated = await store.update(binding.id, {
      sessionStrategy: 'stateless',
      label: 'test-label',
    });
    expect(updated).toBeDefined();
    expect(updated!.sessionStrategy).toBe('stateless');
    expect(updated!.label).toBe('test-label');
    expect(updated!.updatedAt).not.toBe(binding.updatedAt);
    // Original immutable fields preserved
    expect(updated!.adapterId).toBe('telegram-1');
    expect(updated!.agentId).toBe('agent-1');
  });

  it('returns undefined for non-existent binding', async () => {
    const result = await store.update('nonexistent-id', { label: 'test' });
    expect(result).toBeUndefined();
  });

  it('persists updates to disk', async () => {
    const binding = await store.create({
      adapterId: 'telegram-1',
      agentId: 'agent-1',
      projectPath: '/project',
    });
    await store.update(binding.id, { label: 'persisted-label' });
    // Reload store from disk
    const freshStore = new BindingStore(relayDir);
    await freshStore.init();
    expect(freshStore.getById(binding.id)?.label).toBe('persisted-label');
  });
});
```

**Hook test** — create `apps/client/src/layers/entities/binding/model/__tests__/use-update-binding.test.ts`:

```typescript
import { describe, it, expect, vi } from 'vitest';
import { renderHook, waitFor } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { TransportProvider } from '@/layers/shared/model';
import { createMockTransport } from '@dorkos/test-utils';
import { useUpdateBinding } from '../use-update-binding';
import { BINDINGS_QUERY_KEY } from '../use-bindings';

describe('useUpdateBinding', () => {
  it('calls transport.updateBinding and invalidates cache', async () => {
    const queryClient = new QueryClient();
    const mockTransport = createMockTransport();
    const invalidateSpy = vi.spyOn(queryClient, 'invalidateQueries');

    mockTransport.updateBinding = vi.fn().mockResolvedValue({ id: '1', label: 'updated' });

    const wrapper = ({ children }) => (
      <QueryClientProvider client={queryClient}>
        <TransportProvider transport={mockTransport}>{children}</TransportProvider>
      </QueryClientProvider>
    );

    const { result } = renderHook(() => useUpdateBinding(), { wrapper });
    result.current.mutate({ id: '1', updates: { label: 'updated' } });

    await waitFor(() => {
      expect(mockTransport.updateBinding).toHaveBeenCalledWith('1', { label: 'updated' });
      expect(invalidateSpy).toHaveBeenCalledWith(
        expect.objectContaining({ queryKey: [...BINDINGS_QUERY_KEY] }),
      );
    });
  });
});
```

