Create the `BindingList` component for managing bindings in a structured list view, and integrate it as a new tab in the RelayPanel.

## Implementation Steps

### Step 1: Create BindingList component

Create `apps/client/src/layers/features/relay/ui/BindingList.tsx`:

```typescript
import { useState } from 'react';
import { AnimatePresence, motion } from 'motion/react';
import { Link2, MoreVertical, Pencil, Plus, Trash2, ArrowRight } from 'lucide-react';
import {
  Badge,
  Button,
  Skeleton,
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/layers/shared/ui';
import { useBindings, useDeleteBinding, useUpdateBinding } from '@/layers/entities/binding';
import { useAdapterCatalog } from '@/layers/entities/relay';
import type { AdapterBinding, SessionStrategy } from '@dorkos/shared/relay-schemas';
import { BindingDialog } from '@/layers/features/mesh/ui/BindingDialog';

interface BindingListProps {
  enabled: boolean;
}

/** Structured list view for managing adapter-agent bindings with CRUD actions. */
export function BindingList({ enabled }: BindingListProps) {
  const { data: bindings = [], isLoading } = useBindings();
  const { data: catalog = [] } = useAdapterCatalog(enabled);
  const { mutate: deleteBinding } = useDeleteBinding();
  const { mutate: updateBinding } = useUpdateBinding();
  const [deleteTarget, setDeleteTarget] = useState<AdapterBinding | null>(null);
  const [editTarget, setEditTarget] = useState<AdapterBinding | null>(null);
  const [createDialogOpen, setCreateDialogOpen] = useState(false);

  // Helper: find adapter display info from catalog
  const getAdapterInfo = (adapterId: string) => {
    for (const entry of catalog) {
      const inst = entry.instances.find((i) => i.id === adapterId);
      if (inst) return { manifest: entry.manifest, displayName: inst.status.displayName || adapterId };
    }
    return null;
  };

  if (isLoading) {
    return (
      <div className="space-y-2 p-4">
        {[1, 2, 3].map((i) => (
          <Skeleton key={i} className="h-14 w-full rounded-lg" />
        ))}
      </div>
    );
  }

  if (bindings.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center gap-3 p-8 text-center">
        <Link2 className="size-8 text-muted-foreground" />
        <div>
          <p className="text-sm font-medium">No bindings configured</p>
          <p className="text-xs text-muted-foreground">
            Create your first binding to route messages from adapters to agents.
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={() => setCreateDialogOpen(true)}>
          <Plus className="mr-1 size-3" />
          Add Binding
        </Button>
      </div>
    );
  }

  return (
    <div className="space-y-3 p-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
          Bindings ({bindings.length})
        </h3>
        <Button variant="outline" size="sm" onClick={() => setCreateDialogOpen(true)}>
          <Plus className="mr-1 size-3" />
          Add Binding
        </Button>
      </div>

      {/* Binding rows */}
      <div className="space-y-2">
        <AnimatePresence initial={false}>
          {bindings.map((binding) => {
            const adapterInfo = getAdapterInfo(binding.adapterId);
            return (
              <motion.div
                key={binding.id}
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                transition={{ duration: 0.15 }}
                className="flex items-center justify-between rounded-lg border p-3"
              >
                <div className="flex items-center gap-2 overflow-hidden">
                  {/* Adapter info */}
                  <div className="flex items-center gap-1.5">
                    {adapterInfo?.manifest.iconEmoji && (
                      <span className="text-sm" role="img" aria-hidden>
                        {adapterInfo.manifest.iconEmoji}
                      </span>
                    )}
                    <span className="text-sm font-medium truncate">
                      {adapterInfo?.displayName ?? binding.adapterId}
                    </span>
                  </div>

                  <ArrowRight className="size-3 shrink-0 text-muted-foreground" />

                  {/* Agent info */}
                  <span className="text-sm truncate text-muted-foreground">
                    {binding.agentId}
                  </span>

                  {/* Strategy badge */}
                  <Badge variant="secondary" className="shrink-0 text-xs">
                    {binding.sessionStrategy}
                  </Badge>

                  {/* Channel type badge (if set) */}
                  {binding.channelType && (
                    <Badge variant="outline" className="shrink-0 text-xs">
                      {binding.channelType}
                    </Badge>
                  )}
                </div>

                {/* Actions menu */}
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" size="sm" className="size-7 shrink-0 p-0" aria-label="Binding actions">
                      <MoreVertical className="size-4" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuItem onClick={() => setEditTarget(binding)}>
                      <Pencil className="mr-2 size-3.5" />
                      Edit
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      onClick={() => setDeleteTarget(binding)}
                      className="text-red-600 focus:text-red-600"
                    >
                      <Trash2 className="mr-2 size-3.5" />
                      Delete
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </motion.div>
            );
          })}
        </AnimatePresence>
      </div>

      {/* Delete confirmation dialog */}
      <AlertDialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
