export function useAdapterEvents(adapterId: string | null) {
  const transport = useTransport();
  return useQuery({
    queryKey: ['relay', 'adapters', adapterId, 'events'],
    queryFn: () => transport.getAdapterEvents(adapterId!),
    enabled: !!adapterId,
    refetchInterval: 5_000,
  });
}
