      </div>
    );
  }

  const events = data?.events ?? [];
  const filteredEvents = filter === 'all'
    ? events
    : events.filter((e) => e.subject === filter);

  if (events.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center gap-2 p-6 text-center">
        <Activity className="size-6 text-muted-foreground" />
        <p className="text-sm text-muted-foreground">No events recorded</p>
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col">
      {/* Header with filter */}
      <div className="flex items-center justify-between border-b px-3 py-2">
        <h4 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
          Events
        </h4>
        <Select value={filter} onValueChange={setFilter}>
          <SelectTrigger className="h-7 w-[130px] text-xs">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All types</SelectItem>
            {ALL_EVENT_TYPES.map((type) => (
              <SelectItem key={type} value={type}>
                {EVENT_TYPE_LABELS[type]}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      {/* Event list */}
      <div
        ref={scrollRef}
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto p-2"
      >
        {filteredEvents.map((event) => {
          const meta: AdapterEventMetadata | null = event.metadata
            ? JSON.parse(event.metadata)
            : null;
          const time = new Date(event.sentAt).toLocaleTimeString('en-US', {
            hour12: false,
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit',
          });
          return (
            <div key={event.id} className="flex items-start gap-2 py-1">
              <span className="shrink-0 font-mono text-xs tabular-nums text-muted-foreground">
                {time}
              </span>
              <Badge
                variant="secondary"
                className={cn('shrink-0 text-[10px]', EVENT_TYPE_COLORS[event.subject] ?? '')}
              >
                {EVENT_TYPE_LABELS[event.subject] ?? event.subject}
              </Badge>
              <span className="break-words text-xs">
                {meta?.message ?? event.subject}
              </span>
            </div>
          );
        })}
      </div>

      {/* Jump to bottom button (shown when user has scrolled up) */}
      {!isAtBottom && (
        <div className="flex justify-center border-t py-1">
          <Button
            variant="ghost"
            size="sm"
            onClick={jumpToBottom}
            className="h-6 text-xs"
          >
            <ArrowDown className="mr-1 size-3" />
            Jump to bottom
          </Button>
        </div>
      )}
    </div>
  );
}
